import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { User, Mail, Lock, UserCheck, ArrowRight, Loader2 } from 'lucide-react';

const Registro = () => {
  const navigate = useNavigate();
  const [cargando, setCargando] = useState(false);
  const [formData, setFormData] = useState({
    nombre: '',
    correo: '',
    password: '',
    rol: 'cliente'
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegistro = async (e) => {
    e.preventDefault();
    setCargando(true);
    
    try {
      const response = await fetch("http://localhost:5000/api/auth/registro", {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.msg || "Error en el registro");
      }

      alert("¡Cuenta creada con éxito! Ya puedes iniciar sesión.");
      navigate('/login');
    } catch (error) {
      alert(error.message);
    } finally {
      setCargando(false);
    }
  };

  return (
    <div style={containerStyle}>
      <div style={cardStyle}>
        <div style={{ textAlign: 'center', marginBottom: '25px' }}>
          <h2>Crear una cuenta</h2>
        </div>

        <form onSubmit={handleRegistro}>
          <div style={inputGroup}>
            <label style={labelStyle}>Nombre Completo</label>
            <div style={inputWrapper}>
              <User size={18} color="#94a3b8" />
              <input name="nombre" style={rawInput} required onChange={handleChange} placeholder="Ej: Juan Pérez" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Correo Electrónico</label>
            <div style={inputWrapper}>
              <Mail size={18} color="#94a3b8" />
              <input name="correo" type="email" style={rawInput} required onChange={handleChange} placeholder="email@ejemplo.com" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Contraseña</label>
            <div style={inputWrapper}>
              <Lock size={18} color="#94a3b8" />
              <input name="password" type="password" style={rawInput} required onChange={handleChange} placeholder="••••••••" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Tipo de cuenta</label>
            <div style={inputWrapper}>
              <UserCheck size={18} color="#94a3b8" />
              <select name="rol" style={rawInput} value={formData.rol} onChange={handleChange}>
                <option value="cliente">Buscar ofertas (Cliente)</option>
                <option value="vendedor">Publicar ofertas (Vendedor)</option>
              </select>
            </div>
          </div>

          <button type="submit" style={btnSubmit} disabled={cargando}>
            {cargando ? <Loader2 className="spinner" /> : "Registrarme"} <ArrowRight size={18} />
          </button>
        </form>
      </div>
      <style>{`.spinner { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

// ... (Manten los estilos que ya tenías)
export default Registro;
